from vex_sdk.policies import CybersecurityPolicy

@vex.filter(policy=CybersecurityPolicy.HUMAN_APPROVAL_REQUIRED)
def critical_action_filter(message, context):
    actions = ['shutdown', 'isolate', 'block_ip', 'quarantine']
    if any(action in message.lower() for action in actions):
        return {
            "status": "PENDING_HUMAN",
            "message": "CRITICAL ACTION REQUIRES HUMAN APPROVAL",
            "context": context.get('threat_intel', {})
        }
    return message

# Apply to incident response agent
incident_responder = autogen.AssistantAgent(
    name="IncidentResponder",
    reply_filter=critical_action_filter
)
